// com.google.javascript.jscomp.CheckUnreachableCodeTest::testSuppression
  public void testSuppression() {
    assertUnreachable("if(false) { }");

    testSame(
        "\n" +
        "if(false) { }");

    testSame(
        "\n" +
        "function f() { if(false) { } }");

    testSame(
        "\n" +
        "function f() { if(false) { } }");

    assertUnreachable(
        "\n" +
        "function f() { if(false) { } }\n" +
        "function g() { if(false) { } }\n");

    testSame(
        "\n" +
        "function f() {\n" +
        "  function g() { if(false) { } }\n" +
        "  if(false) { } }\n");

    assertUnreachable(
        "function f() {\n" +
        "  \n" +
        "  function g() { if(false) { } }\n" +
        "  if(false) { } }\n");

    testSame(
        "function f() {\n" +
        "  \n" +
        "  function g() { if(false) { } }\n" +
        "}\n");
  }

